import React, { useState } from 'react';
import { Package, DollarSign, Calendar, Image as ImageIcon, X } from 'lucide-react';

const FormularioOferta = ({ onSave, onCancel }) => {
  const [formData, setFormData] = useState({
    producto: '',
    precio: '',
    vencimiento: '',
    descripcion: ''
  });

  const handleSubmit = (e) => {
    e.preventDefault();
    // Validación básica: El precio debe ser un número positivo
    if (parseFloat(formData.precio) <= 0) {
      alert("Por favor, ingresa un precio válido.");
      return;
    }
    onSave(formData);
  };

  return (
    <div style={formCardStyle}>
      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '20px' }}>
        <h3>Nueva Oferta</h3>
        <button onClick={onCancel} style={btnCerrar}><X size={20} /></button>
      </div>

      <form onSubmit={handleSubmit}>
        <div style={inputGroup}>
          <label style={labelStyle}><Package size={16} /> Producto</label>
          <input 
            style={inputStyle} 
            type="text" 
            placeholder="Ej: Leche Larga Vida 1L" 
            required
            value={formData.producto}
            onChange={(e) => setFormData({...formData, producto: e.target.value})}
          />
        </div>

        <div style={{ display: 'flex', gap: '20px' }}>
          <div style={{ ...inputGroup, flex: 1 }}>
            <label style={labelStyle}><DollarSign size={16} /> Precio Oferta</label>
            <input 
              style={inputStyle} 
              type="number" 
              placeholder="0.00" 
              required
              value={formData.precio}
              onChange={(e) => setFormData({...formData, precio: e.target.value})}
            />
          </div>
          <div style={{ ...inputGroup, flex: 1 }}>
            <label style={labelStyle}><Calendar size={16} /> Vencimiento</label>
            <input 
              style={inputStyle} 
              type="date" 
              required
              value={formData.vencimiento}
              onChange={(e) => setFormData({...formData, vencimiento: e.target.value})}
            />
          </div>
        </div>

        <div style={inputGroup}>
          <label style={labelStyle}>Descripción / Nota</label>
          <textarea 
            style={{ ...inputStyle, height: '80px', resize: 'none' }} 
            placeholder="Ej: Máximo 3 unidades por persona"
            value={formData.descripcion}
            onChange={(e) => setFormData({...formData, descripcion: e.target.value})}
          />
        </div>

        <button type="submit" style={btnPublicar}>Publicar Ahora</button>
      </form>
    </div>
  );
};

/* --- ESTILOS --- */
const formCardStyle = { background: 'white', padding: '30px', borderRadius: '20px', boxShadow: '0 10px 25px rgba(0,0,0,0.05)', border: '1px solid #e2e8f0' };
const inputGroup = { marginBottom: '15px' };
const labelStyle = { display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px', fontWeight: '600', color: '#1e293b' };
const inputStyle = { width: '100%', padding: '12px', borderRadius: '10px', border: '1px solid #cbd5e1', boxSizing: 'border-box' };
const btnPublicar = { width: '100%', padding: '14px', background: '#1e293b', color: 'white', border: 'none', borderRadius: '12px', fontWeight: 'bold', cursor: 'pointer', marginTop: '10px' };
const btnCerrar = { background: 'none', border: 'none', cursor: 'pointer', color: '#64748b' };

export default FormularioOferta;
